CREATE TABLE "benefits" ("id" UUID NOT NULL DEFAULT gen_random_uuid(), "company_id" UUID NOT NULL, "code" VARCHAR(50) NOT NULL, "name" VARCHAR(160) NOT NULL, "type" VARCHAR(30) NOT NULL, "status" VARCHAR(20) NOT NULL DEFAULT 'ACTIVE', "created_at" TIMESTAMPTZ(6) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMPTZ(6) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "benefits_pkey" PRIMARY KEY ("id"));
CREATE TABLE "benefit_plans" ("id" UUID NOT NULL DEFAULT gen_random_uuid(), "benefit_id" UUID NOT NULL, "name" VARCHAR(160) NOT NULL, "employee_amount" DECIMAL(15,2) NOT NULL DEFAULT 0, "company_amount" DECIMAL(15,2) NOT NULL DEFAULT 0, "copay_amount" DECIMAL(15,2), "valid_from" DATE NOT NULL, "valid_to" DATE, "status" VARCHAR(20) NOT NULL DEFAULT 'ACTIVE', "created_at" TIMESTAMPTZ(6) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "benefit_plans_pkey" PRIMARY KEY ("id"));
CREATE TABLE "benefit_enrollments" ("id" UUID NOT NULL DEFAULT gen_random_uuid(), "employment_contract_id" UUID NOT NULL, "benefit_plan_id" UUID NOT NULL, "valid_from" DATE NOT NULL, "valid_to" DATE, "status" VARCHAR(20) NOT NULL DEFAULT 'ACTIVE', "reason" VARCHAR(1000), "created_at" TIMESTAMPTZ(6) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "benefit_enrollments_pkey" PRIMARY KEY ("id"));
CREATE TABLE "benefit_enrollment_history" ("id" UUID NOT NULL DEFAULT gen_random_uuid(), "benefit_enrollment_id" UUID NOT NULL, "action" VARCHAR(30) NOT NULL, "reason" VARCHAR(1000), "occurred_at" TIMESTAMPTZ(6) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "benefit_enrollment_history_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "benefits_company_code_key" ON "benefits"("company_id","code"); CREATE UNIQUE INDEX "benefit_plans_benefit_name_start_key" ON "benefit_plans"("benefit_id","name","valid_from"); CREATE INDEX "benefit_enrollments_contract_status_idx" ON "benefit_enrollments"("employment_contract_id","status");
ALTER TABLE "benefits" ADD CONSTRAINT "benefits_company_fkey" FOREIGN KEY ("company_id") REFERENCES "companies"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "benefit_plans" ADD CONSTRAINT "benefit_plans_benefit_fkey" FOREIGN KEY ("benefit_id") REFERENCES "benefits"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "benefit_enrollments" ADD CONSTRAINT "benefit_enrollments_contract_fkey" FOREIGN KEY ("employment_contract_id") REFERENCES "employment_contracts"("id") ON DELETE RESTRICT ON UPDATE CASCADE, ADD CONSTRAINT "benefit_enrollments_plan_fkey" FOREIGN KEY ("benefit_plan_id") REFERENCES "benefit_plans"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "benefit_enrollment_history" ADD CONSTRAINT "benefit_enrollment_history_enrollment_fkey" FOREIGN KEY ("benefit_enrollment_id") REFERENCES "benefit_enrollments"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
